@startuml
skinparam classAttributeIconSize 0

class "自動販売機" {
    - int 投入金額

    + void 商品情報を追加する(Integer 商品番号，Product 商品信息)
    + void 在庫を補充する(Integer 商品番号，Integer 在庫数)

    + boolean お金を投入する(int 希望金額)
    + BuyResult 商品を購入する(int 商品番号)
    + int 返金を受け取る()
